What does this program print?

```cpp
#include <iostream>

class Label {
    std::string m_text;
public:
    Label(std::string t) : m_text{ t } {}
    void show() & {
        std::cout << "lval: " << m_text << "\n";
    }
    void show() && {
        std::cout << "rval: " << m_text << "\n";
    }
};

int main() {
    Label a{ "hello" };
    a.show();
    Label{ "world" }.show();
}
```

